@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings
@using sv_48c83b44c1f74d769687ed1bb5e915dd.Models

<div class="settings-section">
    <h3>Profile</h3>
    <p class="text-muted">Manage your personal information</p>
    <hr />

    @if (_profile is not null)
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="avatar-preview text-center">
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle mb-2" width="120" height="120" />
                    <div class="mb-2">
                        <label class="form-label">Avatar URL</label>
                        <input type="text" class="form-control form-control-sm" @bind="_avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (_showSuccess)
        {
            <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                Profile saved successfully!
                <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
            </div>
        }
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border"></div>
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _profile;
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && _profile != Profile)
        {
            _profile = Profile;
            ResetFields();
        }
    }

    private void ResetFields()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _avatarUrl = _profile.AvatarUrl;
        _bio = _profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await OnSave.InvokeAsync(updated);
        _profile = updated;
        _saving = false;
        _showSuccess = true;
    }

    private void Discard()
    {
        ResetFields();
        _showSuccess = false;
    }
}

@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings
@using sv_48c83b44c1f74d769687ed1bb5e915dd.Models

<div class="settings-section">
    <h3>Notifications</h3>
    <p class="text-muted">Configure how you receive notifications</p>
    <hr />

    @if (_prefs is not null)
    {
        <div class="mb-4">
            <h5>Notification Channels</h5>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@_emailNotifications"
                       @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@_pushNotifications"
                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck channels you want to receive notifications from</p>
            @foreach (var channel in _mutedChannels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                           checked="@channel.IsMuted"
                           @onchange="e => channel.IsMuted = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="@($"ch-{channel.Name}")">
                        #@channel.Name
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>

        @if (_showSuccess)
        {
            <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                Notification preferences saved!
                <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
            </div>
        }
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border"></div>
        </div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _mutedChannels = [];
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _prefs != Prefs)
        {
            _prefs = Prefs;
            _emailNotifications = _prefs.EmailNotifications;
            _pushNotifications = _prefs.PushNotifications;
            _weeklyDigest = _prefs.WeeklyDigest;
            _mutedChannels = _prefs.MutedChannels
                .Select(c => new ChannelState { Name = c, IsMuted = true })
                .ToList();
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var mutedList = _mutedChannels.Where(c => c.IsMuted).Select(c => c.Name).ToList();
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedList);
        await OnSave.InvokeAsync(updated);
        _prefs = updated;
        _saving = false;
        _showSuccess = true;
    }

    private class ChannelState
    {
        public string Name { get; set; } = "";
        public bool IsMuted { get; set; }
    }
}

@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="card card-body mt-2">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="alert alert-success py-2">Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _saving;
    private bool _showSuccess;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _error = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "Passwords do not match.";
            return;
        }

        _saving = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _saving = false;
        _showSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }
}

@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings

@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@DeviceName</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string DeviceName { get; set; } = "";
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings
@using sv_48c83b44c1f74d769687ed1bb5e915dd.Models

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>
    <hr />

    @if (Settings is not null)
    {
        <div class="mb-4">
            <ChangePasswordPanel OnChangePassword="OnChangePassword" />
        </div>

        <div class="mb-4">
            <h5>Two-Factor Authentication</h5>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@Settings.TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        Two-Factor Authentication
                    </label>
                </div>
                <span class="badge @(Settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(Settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            @if (Settings.LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2">
                    Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <div class="mb-4">
            <h5>Active Sessions</h5>
            <div class="table-responsive">
                <table class="table table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Settings.Sessions)
                        {
                            var isCurrent = session == Settings.Sessions.First();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <RevokeSessionDialog Visible="_showRevokeDialog"
                             DeviceName="@(_sessionToRevoke?.Device ?? "")"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="CancelRevoke" />
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border"></div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

