{"file_text": "@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings
@using sv_48c83b44c1f74d769687ed1bb5e915dd.Models

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize the look and feel of the application</p>
    <hr />

    @if (_settings is not null)
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <h5>Compact Mode</h5>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            Enable compact mode
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save
                </button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success alert-dismissible mt-3 fade show" role="alert">
                        Appearance settings saved!
                        <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
                    </div>
                }
            </div>
            <div class="col-md-6">
                <AppearancePreview Theme="@_theme"
                                   FontSize="@_fontSize"
                                   Language="@_language"
                                   CompactMode="@_compactMode" />
            </div>
        </div>
    }
    else
    {
        <div class="text-center py-4">
            <div class="spinner-border"></div>
        </div>
    }
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private bool _showSuccess;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override void OnParametersSet()
    {
        if (Settings is not null && _settings != Settings)
        {
            _settings = Settings;
            _theme = _settings.Theme;
            _fontSize = _settings.FontSize;
            _language = _settings.Language;
            _compactMode = _settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _settings = updated;
        _saving = false;
        _showSuccess = true;
    }
}
