@page "/settings"
@namespace sv_48c83b44c1f74d769687ed1bb5e915dd.Components.Pages.Settings
@rendermode InteractiveServer
@using sv_48c83b44c1f74d769687ed1bb5e915dd.Models
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionSelected="s => _activeSection = s" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection Profile="@_profile" OnSave="SaveProfileAsync" />
                break;
            case "Notifications":
                <NotificationsSection Prefs="@_notificationPrefs" OnSave="SaveNotificationsAsync" />
                break;
            case "Security":
                <SecuritySection Settings="@_securitySettings"
                                 OnChangePassword="ChangePasswordAsync"
                                 OnRevokeSession="RevokeSessionAsync" />
                break;
            case "Appearance":
                <AppearanceSection Settings="@_appearanceSettings" OnSave="SaveAppearanceAsync" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        // Load all settings concurrently
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifTask.Result;
        _securitySettings = securityTask.Result;
        _appearanceSettings = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
    }
}

