.settings-layout {
    display: flex;
    gap: 0;
    min-height: 80vh;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #495057;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
    cursor: pointer;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
    font-weight: 600;
}

/* Avatar */
.avatar-preview {
    padding: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    background: #f8f9fa;
}

.avatar-preview img {
    object-fit: cover;
}

/* Appearance Preview */
.appearance-preview {
    position: sticky;
    top: 1rem;
}

.preview-body {
    border-radius: 0.375rem;
    padding: 1.25rem;
    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .btn-primary {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

.preview-dark .btn-outline-secondary {
    color: #a6adc8;
    border-color: #a6adc8;
}

.preview-dark .text-muted {
    color: #a6adc8 !important;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

.preview-body.compact {
    padding: 0.5rem 0.75rem;
    line-height: 1.3;
}

.preview-body.compact p {
    margin-bottom: 0.25rem;
}

.preview-body.compact .mb-2 {
    margin-bottom: 0.25rem !important;
}

/* Change password panel */
.change-password-panel .card {
    border-color: #dee2e6;
}

/* Session table */
.table th {
    font-weight: 600;
    font-size: 0.875rem;
    text-transform: uppercase;
    color: #6c757d;
}

/* Modal backdrop fix */
.modal-backdrop {
    z-index: 1040;
}

.modal {
    z-index: 1050;
}

